/**
 * @summary List/search riders
 */
export const getListRidersUrl = (params?: ListRidersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/trips/riders?${stringifiedParams}`
    : `/api/trips/riders`;
};

export const listRiders = async (
  params?: ListRidersParams,
  options?: RequestInit,
): Promise<RidersListResponse> => {
  return customFetch<RidersListResponse>(getListRidersUrl(params), {
    ...options,
    method: "GET",
  });
};

